@pytest.mark.parametrize("code, path, expected", DATA_POINTS)
def test_data_point(code: str, path: str, expected: str) -> None:
    country = load_country(code)
    obj = country
    for part in path.split("."):
        obj = getattr(obj, part)
    assert expected in str(obj), (
        f"{code}.{path} = {str(obj)!r}, expected to contain {expected!r}"
    )
